  1→import { Injectable } from '@nestjs/common';
  2→
  3→import { OpensearchConversationalService } from '@modules/opensearch/opensearch-conversational.service';
  4→import { OpensearchService } from '@modules/opensearch/opensearch.service';
  5→
  6→import { LogExecution } from '@decorators/log-execution.decorator';
  7→
  8→import { ClarificationQuestionDto } from '@dto/conversational-search/clarification-question.dto';
  9→import { ClarificationAnswerDto } from '@dto/conversational-search/conversational-search-request.dto';
 10→import { ConversationalSearchResponseDto } from '@dto/conversational-search/conversational-search-response.dto';
 11→
 12→const OCCASION_PATTERN =
 13→	/\b(casual|everyday|sports|outdoor|corporate|business|event|fundraiser|formal|party|wedding|graduation|holiday|school|gym|running|hiking|cycling|yoga)\b/i;
 14→
 15→const MIN_CLARIFICATIONS_NEEDED = 2;
 16→
 17→@Injectable()
 18→export class ConversationalSearchService {
 19→	constructor(
 20→		private readonly opensearchConversationalService: OpensearchConversationalService,
 21→		private readonly opensearchService: OpensearchService,
 22→	) {}
 23→
 24→	private readonly CLARIFICATION_RULES: {
 25→		id: string;
 26→		check: (text: string) => boolean;
 27→		question: string;
 28→		options: { label: string; value: string }[];
 29→	}[] = [
 30→		{
 31→			id: 'gender',
 32→			check: (text) =>
 33→				!this.opensearchConversationalService.detectGenderProductTypes({ text }),
 34→			question: 'Who are these products for?',
 35→			options: [
 36→				{ label: 'Men', value: 'men' },
 37→				{ label: 'Women', value: 'women' },
 38→				{ label: 'Youth / Kids', value: 'youth' },
 39→				{ label: 'Mixed group', value: 'unisex' },
 40→			],
 41→		},
 42→		{
 43→			id: 'price',
 44→			check: (text) => !this.opensearchConversationalService.detectPriceLevels({ text }),
 45→			question: 'What is your budget range?',
 46→			options: [
 47→				{ label: 'Budget (under $10)', value: 'budget' },
 48→				{ label: 'Mid-range ($10–$20)', value: 'midrange' },
 49→				{ label: 'Premium ($20+)', value: 'premium' },
 50→			],
 51→		},
 52→		{
 53→			id: 'occasion',
 54→			check: (text) => !OCCASION_PATTERN.test(text),
 55→			question: 'What is the occasion or intended use?',
 56→			options: [
 57→				{ label: 'Casual / Everyday', value: 'casual' },
 58→				{ label: 'Sports / Outdoor', value: 'sports' },
 59→				{ label: 'Corporate / Business', value: 'corporate' },
 60→				{ label: 'Event / Fundraiser', value: 'event' },
 61→			],
 62→		},
 63→	];
 64→
 65→	@LogExecution({
 66→		paramFormatter: (
 67→			params: [
 68→				{
 69→					message: string;
 70→					conversationId?: string;
 71→					clarifications?: ClarificationAnswerDto[];
 72→				},
 73→			],
 74→		) => ({
 75→			message: params[0].message,
 76→			conversationId: params[0].conversationId,
 77→			hasClarifications: !!params[0].clarifications?.length,
 78→		}),
 79→		responseFormatter: (response: ConversationalSearchResponseDto) => ({
 80→			needsClarification: response.needsClarification,
 81→			conversationId: response.conversationId,
 82→			total: response.total,
 83→		}),
 84→	})
 85→	async chat({
 86→		message,
 87→		conversationId,
 88→		clarifications,
 89→	}: {
 90→		message: string;
 91→		conversationId?: string;
 92→		clarifications?: ClarificationAnswerDto[];
 93→	}): Promise<ConversationalSearchResponseDto> {
 94→		if (conversationId) {
 95→			return this.handleContinuation({ message, conversationId });
 96→		}
 97→
 98→		if (!clarifications?.length) {
 99→			return this.handleNewConversation({ message });
100→		}
101→
102→		return this.handleWithClarifications({ message, clarifications });
103→	}
104→
105→	private async handleContinuation({
106→		message,
107→		conversationId,
108→	}: {
109→		message: string;
110→		conversationId: string;
111→	}): Promise<ConversationalSearchResponseDto> {
112→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
113→			text: message,
114→		});
115→		const normalized = this.opensearchConversationalService.normalizeQuery({
116→			text: sanitized,
117→		});
118→
119→		const { products, answer } =
120→			await this.opensearchConversationalService.searchProducts({
121→				queryText: normalized,
122→				memoryId: conversationId,
123→				llmQuestion: message,
124→			});
125→
126→		return {
127→			needsClarification: false,
128→			conversationId,
129→			query: normalized,
130→			summary: answer ?? `Found ${products.length} products matching your request.`,
131→			total: products.length,
132→			products,
133→		};
134→	}
135→
136→	private async handleNewConversation({
137→		message,
138→	}: {
139→		message: string;
140→	}): Promise<ConversationalSearchResponseDto> {
141→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
142→			text: message,
143→		});
144→
145→		const triggeredRules = this.CLARIFICATION_RULES.filter((rule) =>
146→			rule.check(sanitized),
147→		);
148→
149→		const hasStrongSignal = this.hasStrongProductSignal({ text: sanitized });
150→
151→		if (triggeredRules.length >= MIN_CLARIFICATIONS_NEEDED && !hasStrongSignal) {
152→			const questions: ClarificationQuestionDto[] = triggeredRules.map((rule) => ({
153→				id: rule.id,
154→				question: rule.question,
155→				options: rule.options,
156→			}));
157→
158→			return { needsClarification: true, questions };
159→		}
160→
161→		return this.handleWithClarifications({ message, clarifications: [] });
162→	}
163→
164→	private async handleWithClarifications({
165→		message,
166→		clarifications,
167→	}: {
168→		message: string;
169→		clarifications: ClarificationAnswerDto[];
170→	}): Promise<ConversationalSearchResponseDto> {
171→		const clarificationParts = clarifications.map((c) => {
172→			const rule = this.CLARIFICATION_RULES.find((r) => r.id === c.questionId);
173→			const option = rule?.options.find((o) => o.value === c.answer);
174→			return option?.label ?? c.answer;
175→		});
176→
177→		const enrichedQuery = [message, ...clarificationParts].filter(Boolean).join(' ');
178→
179→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
180→			text: enrichedQuery,
181→		});
182→		const normalized = this.opensearchConversationalService.normalizeQuery({
183→			text: sanitized,
184→		});
185→
186→		const conversationId = await this.opensearchService.createConversation({
187→			name: message.substring(0, 50),
188→		});
189→
190→		const { products, answer } =
191→			await this.opensearchConversationalService.searchProducts({
192→				queryText: normalized,
193→				memoryId: conversationId,
194→				llmQuestion: enrichedQuery,
195→			});
196→
197→		return {
198→			needsClarification: false,
199→			conversationId,
200→			query: normalized,
201→			summary: answer ?? `Found ${products.length} products matching your request.`,
202→			total: products.length,
203→			products,
204→		};
205→	}
206→
207→	private hasStrongProductSignal({ text }: { text: string }): boolean {
208→		const strongSignals =
209→			/\b(polo|hoodie|jacket|hat|cap|bag|mug|pen|notebook|shirt|pants|shorts|socks|shoes|sneakers|sweatshirt|fleece|vest|beanie|gloves|scarf|backpack|tote|water bottle|tumbler|keychain|lanyard|umbrella|polo shirt|t-shirt|tank top|zip-up|half-zip|long-sleeve|short-sleeve|crewneck|v-neck)\b/i;
210→		return strongSignals.test(text) && text.split(' ').length >= 4;
211→	}
212→
213→	renderChatPageHtml(): string {
214→		return `<!DOCTYPE html>
215→<html>
216→<head>
217→  <meta charset="utf-8">
218→  <title>Conversational Search</title>
219→  <style>
220→    * { box-sizing: border-box; }
221→    body { font-family: system-ui, sans-serif; margin: 0; background: #f5f5f5; display: flex; flex-direction: column; height: 100vh; }
222→    #header { padding: 16px 20px; background: #1e40af; color: #fff; font-size: 18px; font-weight: 600; }
223→    #chat { flex: 1; overflow-y: auto; padding: 20px; display: flex; flex-direction: column; gap: 12px; }
224→    .msg { max-width: 70%; padding: 10px 14px; border-radius: 12px; font-size: 14px; line-height: 1.5; }
225→    .msg.user { align-self: flex-end; background: #2563eb; color: #fff; }
226→    .msg.bot { align-self: flex-start; background: #fff; border: 1px solid #ddd; }
227→    .products { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 10px; }
228→    .product-card { border: 1px solid #eee; border-radius: 8px; padding: 8px; width: 150px; text-align: center; background: #fafafa; font-size: 12px; }
229→    .product-card img { width: 130px; height: 130px; object-fit: contain; }
230→    .clarifications { display: flex; flex-direction: column; gap: 10px; }
231→    .clarification-q { font-weight: 600; margin-bottom: 4px; }
232→    .options { display: flex; flex-wrap: wrap; gap: 6px; }
233→    .option-btn { padding: 6px 12px; border: 1px solid #2563eb; border-radius: 20px; background: #fff; color: #2563eb; cursor: pointer; font-size: 13px; }
234→    .option-btn.selected { background: #2563eb; color: #fff; }
235→    #form { display: flex; gap: 8px; padding: 12px 20px; background: #fff; border-top: 1px solid #ddd; }
236→    #input { flex: 1; padding: 10px 14px; font-size: 14px; border: 1px solid #ccc; border-radius: 8px; outline: none; }
237→    #send { padding: 10px 20px; background: #2563eb; color: #fff; border: none; border-radius: 8px; cursor: pointer; font-size: 14px; }
238→    #send:disabled { background: #93c5fd; cursor: not-allowed; }
239→  </style>
240→</head>
241→<body>
242→  <div id="header">Conversational Product Search</div>
243→  <div id="chat"></div>
244→  <form id="form">
245→    <input id="input" placeholder="Describe what you're looking for..." autocomplete="off" />
246→    <button id="send" type="submit">Send</button>
247→  </form>
248→  <script>
249→    var conversationId = null;
250→    var pendingClarifications = null;
251→    var pendingMessage = null;
252→
253→    function appendMsg(role, html) {
254→      var div = document.createElement('div');
255→      div.className = 'msg ' + role;
256→      div.innerHTML = html;
257→      document.getElementById('chat').appendChild(div);
258→      document.getElementById('chat').scrollTop = 999999;
259→    }
260→
261→    function renderProducts(products) {
262→      if (!products || !products.length) return '';
263→      return '<div class="products">' + products.slice(0, 10).map(function(p) {
264→        return '<div class="product-card"><img src="' + (p.style_card_image_url || '') + '" onerror="this.style.display=\\'none\\'" /><div>' + p.name + '</div></div>';
265→      }).join('') + '</div>';
266→    }
267→
268→    function renderClarifications(questions) {
269→      pendingClarifications = {};
270→      return '<div class="clarifications">' + questions.map(function(q) {
271→        return '<div><div class="clarification-q">' + q.question + '</div><div class="options" data-id="' + q.id + '">' +
272→          q.options.map(function(o) {
273→            return '<button class="option-btn" data-value="' + o.value + '" onclick="selectOption(this)">' + o.label + '</button>';
274→          }).join('') + '</div></div>';
275→      }).join('') + '<button onclick="submitClarifications()" style="margin-top:10px;padding:8px 16px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">Search</button></div>';
276→    }
277→
278→    function selectOption(btn) {
279→      var group = btn.parentElement;
280→      group.querySelectorAll('.option-btn').forEach(function(b) { b.classList.remove('selected'); });
281→      btn.classList.add('selected');
282→      pendingClarifications[group.dataset.id] = btn.dataset.value;
283→    }
284→
285→    function submitClarifications() {
286→      var clarifications = Object.keys(pendingClarifications).map(function(k) {
287→        return { questionId: k, answer: pendingClarifications[k] };
288→      });
289→      sendRequest({ message: pendingMessage, clarifications: clarifications });
290→    }
291→
292→    function sendRequest(payload) {
293→      document.getElementById('send').disabled = true;
294→      fetch('/api/v1/conversational-search/chat', {
295→        method: 'POST',
296→        headers: { 'Content-Type': 'application/json' },
297→        body: JSON.stringify(payload)
298→      })
299→      .then(function(r) { return r.json(); })
300→      .then(function(data) {
301→        if (data.needsClarification) {
302→          pendingMessage = payload.message;
303→          appendMsg('bot', renderClarifications(data.questions));
304→        } else {
305→          conversationId = data.conversationId;
306→          var html = '';
307→          if (data.summary) html += '<div>' + data.summary + '</div>';
308→          if (data.total) html += '<div style="color:#666;font-size:12px;margin-top:4px;">Found ' + data.total + ' products</div>';
309→          html += renderProducts(data.products);
310→          appendMsg('bot', html);
311→        }
312→      })
313→      .catch(function() { appendMsg('bot', 'Something went wrong. Please try again.'); })
314→      .finally(function() { document.getElementById('send').disabled = false; });
315→    }
316→
317→    document.getElementById('form').addEventListener('submit', function(e) {
318→      e.preventDefault();
319→      var msg = document.getElementById('input').value.trim();
320→      if (!msg) return;
321→      appendMsg('user', msg);
322→      document.getElementById('input').value = '';
323→      pendingMessage = msg;
324→      pendingClarifications = null;
325→      var payload = { message: msg };
326→      if (conversationId) payload.conversationId = conversationId;
327→      sendRequest(payload);
328→    });
329→  </script>
330→</body>
331→</html>`;
332→	}
333→}
