 1→import {
 2→	Body,
 3→	Controller,
 4→	Get,
 5→	Header,
 6→	HttpCode,
 7→	HttpStatus,
 8→	Post,
 9→} from '@nestjs/common';
10→import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
11→
12→import { ConversationalSearchService } from '@modules/rest/conversational-search/conversational-search.service';
13→
14→import { LogExecution } from '@decorators/log-execution.decorator';
15→
16→import { ConversationalSearchRequestDto } from '@dto/conversational-search/conversational-search-request.dto';
17→import { ConversationalSearchResponseDto } from '@dto/conversational-search/conversational-search-response.dto';
18→
19→@ApiTags('Conversational Search')
20→@Controller('conversational-search')
21→export class ConversationalSearchController {
22→	constructor(
23→		private readonly conversationalSearchService: ConversationalSearchService,
24→	) {}
25→
26→	@Post('chat')
27→	@HttpCode(HttpStatus.OK)
28→	@ApiOperation({
29→		summary:
30→			'Chat-based product search with optional clarification and multi-turn support',
31→	})
32→	@ApiResponse({
33→		status: HttpStatus.OK,
34→		description:
35→			'Returns clarification questions or product recommendations with summary',
36→		type: ConversationalSearchResponseDto,
37→	})
38→	@ApiResponse({ status: HttpStatus.BAD_REQUEST, description: 'Invalid request body' })
39→	@LogExecution({
40→		paramFormatter: (params: [ConversationalSearchRequestDto]) => ({
41→			message: params[0].message,
42→			conversationId: params[0].conversationId,
43→			hasClarifications: !!params[0].clarifications?.length,
44→		}),
45→		responseFormatter: (response: ConversationalSearchResponseDto) => ({
46→			needsClarification: response.needsClarification,
47→			total: response.total,
48→		}),
49→	})
50→	async chat(
51→		@Body() body: ConversationalSearchRequestDto,
52→	): Promise<ConversationalSearchResponseDto> {
53→		return this.conversationalSearchService.chat({
54→			message: body.message,
55→			...(body.conversationId !== undefined && { conversationId: body.conversationId }),
56→			...(body.clarifications !== undefined && { clarifications: body.clarifications }),
57→		});
58→	}
59→
60→	@Get('view')
61→	@ApiOperation({ summary: 'Interactive HTML chat interface for conversational search' })
62→	@ApiResponse({ status: HttpStatus.OK, description: 'Returns HTML chat page' })
63→	@Header('Content-Type', 'text/html')
64→	view(): string {
65→		return this.conversationalSearchService.renderChatPageHtml();
66→	}
67→}
