 50→	private async resolveModelIds(): Promise<void> {
 51→		try {
 52→			const modelGroupId = await this.opensearchService.searchModelGroupByName({
 53→				name: MODEL_GROUP_NAME,
 54→			});
 55→
 56→			if (!modelGroupId) {
 57→				this.logger.warn(
 58→					'Conversational search model group not found. Run: npm run cli:dev -- bootstrap-conversational-search',
 59→				);
 60→				return;
 61→			}
 62→
 63→			const models = await this.opensearchService.searchModelsByGroupWithNames({
 64→				modelGroupId,
 65→			});
 66→
 67→			const deployedModels = models.filter((m) => m.model_state === 'DEPLOYED');
 68→
 69→			const embeddingModel = deployedModels.find((m) =>
 70→				m.name.toLowerCase().includes(EMBEDDING_MODEL_PARTIAL_NAME),
 71→			);
 72→			const llmModel = deployedModels.find((m) =>
 73→				m.name.toLowerCase().includes(LLM_MODEL_PARTIAL_NAME),
 74→			);
 75→
 76→			if (embeddingModel && embeddingModel.model_id !== this.embeddingModelId) {
 77→				const previous = this.embeddingModelId;
 78→				this.embeddingModelId = embeddingModel.model_id;
 79→				this.logger.log(
 80→					`Embedding model ID updated: ${previous ?? 'none'} -> ${embeddingModel.model_id}`,
 81→				);
 82→			}
 83→
 84→			if (llmModel && llmModel.model_id !== this.llmModelId) {
