353→	async searchProducts({
354→		queryText,
355→		size = NEURAL_SEARCH_LIMIT,
356→		memoryId,
357→		llmQuestion,
358→	}: {
359→		queryText: string;
360→		size?: number;
361→		memoryId?: string;
362→		llmQuestion?: string;
363→	}): Promise<{ products: IOpensearchProduct[]; answer?: string }> {
364→		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
365→		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
366→		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
367→		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
368→		const brand = this.detectBrand({ text: sanitizedQuery });
369→
370→		const baseFilters: object[] = [{ term: { status: 'active' } }];
371→
372→		if (genderProductTypes) {
373→			baseFilters.push({ terms: { product_type: genderProductTypes } });
374→		}
375→
376→		const priceBoosts: object[] =
377→			priceLevels?.map((level) => ({
378→				term: { price_level: { value: level, boost: 1.5 } },
379→			})) ?? [];
380→
381→		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand], boost: 2 } }] : [];
382→
383→		const searchBody: Record<string, unknown> = {
384→			size,
385→			min_score: 0.4,
386→			query: {
387→				hybrid: {
388→					queries: [
389→						{ bool: { should: [...priceBoosts, ...brandBoosts], filter: baseFilters } },
390→						{
391→							neural: {
392→								product_embedding: {
393→									query_text: normalizedQuery,
394→									model_id: this.getEmbeddingModelId(),
395→									k: size * 5,
396→									filter: { bool: { filter: baseFilters } },
397→								},
398→							},
399→						},
400→					],
401→				},
402→			},
403→			collapse: { field: 'product_id' },
404→			_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
405→		};
406→
407→		if (memoryId && llmQuestion) {
408→			searchBody['ext'] = {
409→				generative_qa_parameters: {
410→					llm_question: llmQuestion,
411→					llm_model: 'gpt-4o-mini',
412→					memory_id: memoryId,
413→					context_size: 5,
414→					message_size: 5,
415→					timeout: 15,
416→				},
417→			};
418→		}
419→
420→		const result = await this.opensearchService.search({
421→			indexName: this.indexName,
422→			searchPipeline: 'conversational-hybrid-search-pipeline',
423→			body: searchBody,
424→		});
425→
426→		const products = result.hits.map((hit) => ({
427→			...(hit._source as IOpensearchProduct),
428→			_id: hit._id,
429→		}));
430→
431→		const ragData = result.ext?.['retrieval_augmented_generation'] as
432→			| { answer?: string }
433→			| undefined;
434→
435→		const answer = ragData?.answer;
436→
437→		const searchResult: { products: IOpensearchProduct[]; answer?: string } = {
438→			products,
439→		};
440→
441→		if (answer !== undefined) {
442→			searchResult.answer = answer;
443→		}
444→
445→		return searchResult;
446→	}
