317→	private async cleanupExistingResources({
318→		indexName,
319→	}: {
320→		indexName: string;
321→	}): Promise<void> {
322→		this.logger.log('Deleting conversational index...');
323→		await this.opensearchService.deleteIndex({ indexName });
324→
325→		this.logger.log('Deleting conversational pipelines...');
326→		await this.opensearchService.deleteSearchPipeline({
327→			pipelineId: CONV_SEARCH_PIPELINE_ID,
328→		});
329→		await this.opensearchService.deleteIngestPipeline({
330→			pipelineId: CONV_INGEST_PIPELINE_ID,
331→		});
332→
333→		this.logger.log('Looking for existing conversational model group...');
334→		const modelGroupId = await this.opensearchService.searchModelGroupByName({
335→			name: CONV_MODEL_GROUP_NAME,
336→		});
337→
338→		if (modelGroupId) {
339→			this.logger.log(`Found model group: ${modelGroupId}, cleaning up models...`);
340→			const models = await this.opensearchService.searchModelsByGroup({ modelGroupId });
341→
342→			for (const model of models) {
343→				if (model.model_state === 'DEPLOYED' || model.model_state === 'DEPLOYING') {
344→					this.logger.log(`Undeploying model: ${model.model_id}`);
345→					await this.opensearchService.undeployModel({ modelId: model.model_id });
346→					await new Promise((resolve) => setTimeout(resolve, 3000));
347→				}
348→
349→				this.logger.log(`Deleting model: ${model.model_id}`);
350→				await this.opensearchService.deleteModel({ modelId: model.model_id });
351→			}
352→
353→			this.logger.log('Deleting model group...');
354→			await this.opensearchService.deleteModelGroup({ modelGroupId });
355→			this.logger.log('Waiting for ML index refresh...');
356→			await new Promise((resolve) => setTimeout(resolve, 10000));
357→		} else {
358→			this.logger.log('No existing conversational model group found');
359→		}
360→
361→		this.logger.log('Cleanup complete');
362→	}
