454→	private setupGracefulShutdown(): void {
455→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
456→
457→		signals.forEach((signal) => {
458→			process.on(signal, () => {
459→				void this.handleShutdown(signal);
460→			});
461→		});
462→
463→		process.on('uncaughtException', (error) => {
464→			this.logger.error(`Uncaught exception: ${error.message}`);
465→			void this.handleShutdown('SIGTERM');
466→		});
467→
468→		process.on('unhandledRejection', (reason) => {
469→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
470→			void this.handleShutdown('SIGTERM');
471→		});
472→	}
473→
474→	private async handleShutdown(signal: string): Promise<void> {
475→		if (this.isShuttingDown) {
476→			this.logger.warn('Force shutdown requested, exiting immediately');
477→			process.exit(1);
478→		}
479→
480→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
481→		this.isShuttingDown = true;
482→		this.isCancelled = true;
483→
484→		try {
485→			if (this.currentOperation) {
486→				this.logger.log('Waiting for current operation to complete...');
487→
488→				const shutdownTimeout = setTimeout(() => {
489→					this.logger.error('Graceful shutdown timeout, forcing exit');
490→					process.exit(1);
491→				}, 30000);
492→
493→				try {
494→					await this.currentOperation;
495→				} finally {
496→					clearTimeout(shutdownTimeout);
497→				}
498→			}
499→
500→			this.logger.log('Graceful shutdown completed');
501→			process.exit(0);
502→		} catch (error) {
503→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
504→			process.exit(1);
505→		}
506→	}
507→}
